settings.dashboardCss:
/* ========================================================== */
/* --- 1. GLOBAL WIDGET OVERRIDES (GLASSMORPHISM) ---         */
/* ========================================================== */
.tb-widget {
    padding: 0 !important;
    border-radius: 20px !important;
    box-shadow: 0px 4px 10px rgba(23, 33, 90, 0.5) !important;
    overflow: hidden !important; 
    background: transparent !important;
    backdrop-filter: blur(12px) saturate(120%);
    -webkit-backdrop-filter: blur(12px) saturate(120%);
    
    /* Spring-like transition for hover effects */
    transition: transform 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275); 
}

/* Hide default titles */
.tb-widget-title,
.tb-widget-header {
    display: none !important;
}

/* Remove backgrounds from Logo (1) and Header Text (3) */
gridster-item:nth-of-type(1) .tb-widget,
gridster-item:nth-of-type(3) .tb-widget {
    box-shadow: none !important;
    backdrop-filter: none !important;
    -webkit-backdrop-filter: none !important;
    background: transparent !important;
}

/* ========================================================== */
/* --- 2. ENTRANCE ANIMATION ASSIGNMENTS ---                  */
/* ========================================================== */

/* Set initial state for all animated widgets */
gridster-item:nth-of-type(2),
gridster-item:nth-of-type(3),
gridster-item:nth-of-type(4),
gridster-item:nth-of-type(5),
gridster-item:nth-of-type(6),
gridster-item:nth-of-type(7),
gridster-item:nth-of-type(n+8) {
    opacity: 0; 
    animation-fill-mode: forwards !important;
}

/* Widget 1: Logo -> No animation */
gridster-item:nth-of-type(1) {
    opacity: 1 !important;
    animation: none !important;
}

/* Widget 2: Navbar -> Slide Down (y:-20 to 0) */
gridster-item:nth-of-type(2) {
    animation: slideDown 0.6s cubic-bezier(0.25, 1, 0.5, 1) forwards;
    animation-delay: 0s !important;
}

/* Widget 3: Header -> Slide Up (y:20 to 0) | Delay: 0.3s */
gridster-item:nth-of-type(3) {
    animation: slideUp20 0.6s cubic-bezier(0.25, 1, 0.5, 1) forwards;
    animation-delay: 0.3s !important;
}

/* Widgets 4-7: KPI Cards -> Slide Up (y:30 to 0) | Delay: 0.5s */
gridster-item:nth-of-type(4),
gridster-item:nth-of-type(5),
gridster-item:nth-of-type(6),
gridster-item:nth-of-type(7) {
    animation: slideUp30 0.6s cubic-bezier(0.25, 1, 0.5, 1) forwards;
    animation-delay: 0.5s !important;
}

/* Widgets 8+: Chart & Insights -> Slide Up (y:40 to 0) | Delay: 0.7s */
gridster-item:nth-of-type(n+8) {
    animation: slideUp40 0.6s cubic-bezier(0.25, 1, 0.5, 1) forwards;
    animation-delay: 0.7s !important;
}

/* ========================================================== */
/* --- 3. HOVER EFFECTS & MICRO-ANIMATIONS ---                */
/* ========================================================== */

/* Spring Hover Scale to 1.02 for KPI Cards and Insight Card */
gridster-item:nth-of-type(4):hover .tb-widget,
gridster-item:nth-of-type(5):hover .tb-widget,
gridster-item:nth-of-type(6):hover .tb-widget,
gridster-item:nth-of-type(7):hover .tb-widget,
gridster-item:nth-of-type(9):hover .tb-widget {
    /*transform: scale(1.02);*/
}

/* Date Pill Hover (Assuming it has a class like .date-pill in Widget 3) */
gridster-item:nth-of-type(3) .date-pill {
    transition: all 0.2s ease;
}
gridster-item:nth-of-type(3) .date-pill:hover {
    transform: scale(1.05);
    background-color: rgba(255, 255, 255, 0.2) !important;
}
gridster-item:nth-of-type(3) .date-pill:active {
    transform: scale(0.95);
}

/* Key Insights Wiggle (Targets any image inside Widget 9) */
gridster-item:nth-of-type(9) img {
    animation: wigglePause 5s infinite;
}

/* ========================================================== */
/* --- 4. KEYFRAMES ---                                       */
/* ========================================================== */

@keyframes slideDown {
    0% { transform: translateY(-20px); opacity: 0; }
    100% { transform: translateY(0); opacity: 1; }
}

@keyframes slideUp20 {
    0% { transform: translateY(20px); opacity: 0; }
    100% { transform: translateY(0); opacity: 1; }
}

@keyframes slideUp30 {
    0% { transform: translateY(30px); opacity: 0; }
    100% { transform: translateY(0); opacity: 1; }
}

@keyframes slideUp40 {
    0% { transform: translateY(40px); opacity: 0; }
    100% { transform: translateY(0); opacity: 1; }
}

/* Wiggle over 2 seconds, then pause for 3 seconds (5s total loop) */
@keyframes wigglePause {
    0%, 40%, 100% { transform: rotate(0deg); }
    5% { transform: rotate(10deg); }
    15% { transform: rotate(-10deg); }
    25% { transform: rotate(10deg); }
    35% { transform: rotate(-10deg); }
}
